class MetricsCollector:
    """Simple in-memory metrics collector for monitoring throughput."""
    
    def __init__(self):
        self._total_requests = 0
        self._total_messages_received = 0
        self._total_messages_sent = 0
        self._total_bytes_received = 0
        self._total_bytes_sent = 0
        self._start_time = time.time()
        self._errors = 0
    
    def record_request(self):
        self._total_requests += 1
    
    def record_message_received(self, size_bytes=0):
        self._total_messages_received += 1
        self._total_bytes_received += size_bytes
    
    def record_message_sent(self, size_bytes=0):
        self._total_messages_sent += 1
        self._total_bytes_sent += size_bytes
    
    def record_error(self):
        self._errors += 1
    
    @property
    def uptime(self):
        return time.time() - self._start_time
    
    @property
    def total_requests(self):
        return self._total_requests
    
    @property
    def throughput_rps(self):
        elapsed = self.uptime
        if elapsed == 0:
            return 0
        return self._total_requests / elapsed
    
    def get_stats(self):
        return {
            "uptime_seconds": self.uptime,
            "total_requests": self._total_requests,
            "total_messages_received": self._total_messages_received,
            "total_messages_sent": self._total_messages_sent,
            "total_bytes_received": self._total_bytes_received,
            "total_bytes_sent": self._total_bytes_sent,
            "errors": self._errors,
            "throughput_rps": self.throughput_rps,
        }


